const zlib = require\('zlib'\)
const fs = require\('fs'\)

const width = 512, height = 512

// PNG signature
const sig = Buffer.from\([137,80,78,71,13,10,26,10]\)

function crc32\(buf\) {
  let c = 0xffffffff
  for \(const b of buf\) {
    c ^= b
    for \(let i = 0; i < 8; i++\) c = \(c & 1\) ? \(0xedb88320 ^ \(c >>> 1\)\) : \(c >>> 1\)
  }
  return \(c ^ 0xffffffff\) >>> 0
}

function chunk\(type, data\) {
  const typeB = Buffer.from\(type\)
  const len = Buffer.alloc\(4\); len.writeUInt32BE\(data.length\)
  const crcVal = crc32\(Buffer.concat\([typeB, data]\)\)
  const crcB = Buffer.alloc\(4\); crcB.writeUInt32BE\(crcVal\)
  return Buffer.concat\([len, typeB, data, crcB]\)
}

// IHDR
const ihdr = Buffer.alloc\(13\)
ihdr.writeUInt32BE\(width, 0\); ihdr.writeUInt32BE\(height, 4\)
ihdr[8]=8; ihdr[9]=2; ihdr[10]=0; ihdr[11]=0; ihdr[12]=0

// Purple #6c63ff rows
const row = Buffer.alloc\(1 + width * 3\)
row[0] = 0
for \(let x = 0; x < width; x++\) { row[1+x*3]=0x6c; row[2+x*3]=0x63; row[3+x*3]=0xff }
const raw = Buffer.concat\(Array\(height\).fill\(row\)\)
const compressed = zlib.deflateSync\(raw\)

const png = Buffer.concat\([sig, chunk\('IHDR', ihdr\), chunk\('IDAT', compressed\), chunk\('IEND', Buffer.alloc\(0\)\)]\)
fs.writeFileSync\('brands/jakite/icons/icon.png', png\)
console.log\('icon.png', png.length, 'bytes'\)
")

